#include &lt;stdio.h&gt;

// To change a variable in the caller's scope, we must receive its physical address.
void update_sensor(int *temp_ptr) {
    if (temp_ptr == NULL) return; // Guard clause against NULL pointers

    // Dereference the pointer to write 95 directly into main's memory.
    *temp_ptr = 95; 
}

int main() {
    int core_temp = 40;

    // We pass the Address-Of core_temp to the function
    update_sensor(&core_temp);

    // Prints 95. The function mutated our local stack variable remotely.
    printf("Current Temp: %d\n", core_temp);

    return 0;
}

