#include &lt;stdio.h&gt;
#include &lt;stdint.h&gt;

void pointer_scaling() {
    uint64_t data[3] = {100, 200, 300};

    // An array name 'decays' into a pointer to its first element.
    uint64_t *ptr = data; // Points to 100

    // Array indexing is secretly just pointer arithmetic!
    // data[2] is literally compiled as *(data + 2)

    printf("Value: %lu\n", *(ptr + 1)); // Prints 200. Physically shifted 8 bytes.

    // Pointer Subtraction yields the number of ELEMENTS between them
    uint64_t *end = &data[2];
    ptrdiff_t diff = end - ptr;
    printf("Elements between: %td\n", diff); // Prints 2, NOT 16 bytes.
}

