#include &lt;stdio.h&gt;

// A generic function that can print an int OR a float.
// It accepts an opaque void* to strip the type, and an enum to define the logic.
void print_generic(void *data, int type_flag) {
    if (type_flag == 1) {
        // We MUST cast the void* back to its true type before dereferencing.
        int *int_ptr = (int *)data;
        printf("Integer: %d\n", *int_ptr);
    } else if (type_flag == 2) {
        float *float_ptr = (float *)data;
        printf("Float: %f\n", *float_ptr);
    }
}

int main() {
    int a = 42;
    float b = 3.14f;
    // Implicitly casts specific pointers to void*
    print_generic(&a, 1);
    print_generic(&b, 2);
    return 0;
}

#include &lt;stdint.h&gt;
#include &lt;stdio.h&gt;

// Engineer tries to interpret a 32-bit hardware sensor float 
// as an integer to check if the top bits (errors) are set.
uint32_t check_sensor_error(float sensor_val) {
    // DANGER: Strict Aliasing Violation (Type Punning via pointer cast)
    uint32_t *raw_bits = (uint32_t *)&sensor_val;

    return (*raw_bits) & 0xF0000000;
}
